import { create } from 'zustand';

export type GameStatus = 'menu' | 'playing' | 'gameover';

interface GameState {
  status: GameStatus;
  playerRole: 'w2' | 'w3' | null;
  playerHp: number;
  enemyHp: number;
  winner: 'player' | 'enemy' | 'draw' | null;
  setStatus: (status: GameStatus) => void;
  setPlayerRole: (role: 'w2' | 'w3' | null) => void;
  setHp: (playerHp: number, enemyHp: number) => void;
  setWinner: (winner: 'player' | 'enemy' | 'draw' | null) => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  status: 'menu',
  playerRole: null,
  playerHp: 100,
  enemyHp: 100,
  winner: null,
  setStatus: (status) => set({ status }),
  setPlayerRole: (role) => set({ playerRole: role }),
  setHp: (playerHp, enemyHp) => set({ playerHp, enemyHp }),
  setWinner: (winner) => set({ winner }),
  resetGame: () => set({ playerHp: 100, enemyHp: 100, winner: null }),
}));

