export const GAME_WIDTH = 960;
export const GAME_HEIGHT = 540;

export const MAX_HP = 100;
export const PLAYER_SPEED = 200;
export const LIGHT_ATTACK_DAMAGE = 10;
export const BLOCK_REDUCTION = 0.5;

// Physics
export const GRAVITY = 800;

export const FLOOR_HEIGHT = 450;

import w2Idle from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_2/Idle (480x96)[frames=5].png';
import w2Walk from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_2/Walk (768x96)[frames=8].png';
import w2Attack from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_2/Attack_1 (384x96)[frames=4].png';
import w2Protect from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_2/Protect (192x96)[frames=2].png';
import w2Hurt from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_2/Hurt (288x96)[frames=3].png';
import w2Dead from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_2/Dead (384x96)[frames=4].png';

import w3Idle from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_3/Idle (480x96)[frames=5].png';
import w3Walk from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_3/Walk (768x96)[frames=8].png';
import w3Attack from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_3/Attack_1 (384x96)[frames=4].png';
import w3Protect from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_3/Protect (288x96)[frames=3].png';
import w3Hurt from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_3/Hurt (192x96)[frames=2].png';
import w3Dead from '../assets/Free_Warrior_Pixel_Art_Sprite_Sheets/Warrior_3/Dead (384x96)[frames=4].png';

export const ASSETS = {
  w2: {
    idle: w2Idle,
    walk: w2Walk,
    attack: w2Attack,
    protect: w2Protect,
    hurt: w2Hurt,
    dead: w2Dead,
  },
  w3: {
    idle: w3Idle,
    walk: w3Walk,
    attack: w3Attack,
    protect: w3Protect,
    hurt: w3Hurt,
    dead: w3Dead,
  }
};

import Phaser from 'phaser';
import { ASSETS } from '../assets';

export class Boot extends Phaser.Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // Generate placeholder for missing images
    this.load.on('loaderror', (file: Phaser.Loader.File) => {
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, w, h);
      g.destroy();
    });

    const CFG = { frameWidth: 96, frameHeight: 96 };

    // Warrior 2
    this.load.spritesheet('w2_idle', ASSETS.w2.idle, CFG);
    this.load.spritesheet('w2_walk', ASSETS.w2.walk, CFG);
    this.load.spritesheet('w2_attack', ASSETS.w2.attack, CFG);
    this.load.spritesheet('w2_protect', ASSETS.w2.protect, CFG);
    this.load.spritesheet('w2_hurt', ASSETS.w2.hurt, CFG);
    this.load.spritesheet('w2_dead', ASSETS.w2.dead, CFG);

    // Warrior 3
    this.load.spritesheet('w3_idle', ASSETS.w3.idle, CFG);
    this.load.spritesheet('w3_walk', ASSETS.w3.walk, CFG);
    this.load.spritesheet('w3_attack', ASSETS.w3.attack, CFG);
    this.load.spritesheet('w3_protect', ASSETS.w3.protect, CFG);
    this.load.spritesheet('w3_hurt', ASSETS.w3.hurt, CFG);
    this.load.spritesheet('w3_dead', ASSETS.w3.dead, CFG);
  }

  create() {
    // Create Animations for W2
    this.anims.create({ key:'w2_idle',    frames:this.anims.generateFrameNumbers('w2_idle',    {start:0,end:4}), frameRate:8,  repeat:-1 });
    this.anims.create({ key:'w2_walk',    frames:this.anims.generateFrameNumbers('w2_walk',    {start:0,end:7}), frameRate:10, repeat:-1 });
    this.anims.create({ key:'w2_attack',  frames:this.anims.generateFrameNumbers('w2_attack',  {start:0,end:3}), frameRate:12, repeat:0  });
    this.anims.create({ key:'w2_protect', frames:this.anims.generateFrameNumbers('w2_protect', {start:0,end:1}), frameRate:8,  repeat:-1 });
    this.anims.create({ key:'w2_hurt',    frames:this.anims.generateFrameNumbers('w2_hurt',    {start:0,end:2}), frameRate:10, repeat:0  });
    this.anims.create({ key:'w2_dead',    frames:this.anims.generateFrameNumbers('w2_dead',    {start:0,end:3}), frameRate:8,  repeat:0  });

    // Create Animations for W3 (protect end=2, hurt end=1)
    this.anims.create({ key:'w3_idle',    frames:this.anims.generateFrameNumbers('w3_idle',    {start:0,end:4}), frameRate:8,  repeat:-1 });
    this.anims.create({ key:'w3_walk',    frames:this.anims.generateFrameNumbers('w3_walk',    {start:0,end:7}), frameRate:10, repeat:-1 });
    this.anims.create({ key:'w3_attack',  frames:this.anims.generateFrameNumbers('w3_attack',  {start:0,end:3}), frameRate:12, repeat:0  });
    this.anims.create({ key:'w3_protect', frames:this.anims.generateFrameNumbers('w3_protect', {start:0,end:2}), frameRate:8,  repeat:-1 });
    this.anims.create({ key:'w3_hurt',    frames:this.anims.generateFrameNumbers('w3_hurt',    {start:0,end:1}), frameRate:10, repeat:0  });
    this.anims.create({ key:'w3_dead',    frames:this.anims.generateFrameNumbers('w3_dead',    {start:0,end:3}), frameRate:8,  repeat:0  });

    this.scene.start('MainMenu');
  }
}

import Phaser from 'phaser';
import { EventBus } from '../EventBus';

export class MainMenu extends Phaser.Scene {
  constructor() {
    super('MainMenu');
  }

  create() {
    const w = this.game.config.width as number;
    const h = this.game.config.height as number;

    // Draw background
    const bg = this.add.graphics();
    bg.fillGradientStyle(0x1A237E, 0x1A237E, 0x0D113A, 0x0D113A, 1);
    bg.fillRect(0, 0, w, h);

    // Let React know Phaser is ready
    EventBus.emit('phaser-ready');

    EventBus.on('start-game', (role: 'w2' | 'w3') => {
      this.scene.start('Game', { role });
    });
  }

  shutdown() {
    EventBus.off('start-game');
  }
}

import Phaser from 'phaser';
import { Boot } from './scenes/Boot';
import { MainMenu } from './scenes/MainMenu';
import { Game } from './scenes/Game';
import { GAME_WIDTH, GAME_HEIGHT } from './constants';

const config: Phaser.Types.Core.GameConfig = {
  type: Phaser.AUTO,
  width: GAME_WIDTH,
  height: GAME_HEIGHT,
  parent: 'game-container',
  backgroundColor: '#1A237E',
  scene: [Boot, MainMenu, Game],
  physics: {
    default: 'arcade',
    arcade: {
      gravity: { y: 0, x: 0 },
      debug: false
    }
  },
  scale: {
    mode: Phaser.Scale.FIT,
    autoCenter: Phaser.Scale.CENTER_BOTH
  }
};

export function startPhaserGame() {
  return new Phaser.Game(config);
}

import Phaser from 'phaser';
import { EventBus } from '../EventBus';
import { useGameStore } from '../store';
import { GAME_WIDTH, GAME_HEIGHT, FLOOR_HEIGHT, PLAYER_SPEED, LIGHT_ATTACK_DAMAGE, BLOCK_REDUCTION } from '../constants';

export class Game extends Phaser.Scene {
  private player!: Phaser.Physics.Arcade.Sprite;
  private enemy!: Phaser.Physics.Arcade.Sprite;

  private playerRole!: 'w2' | 'w3';
  private enemyRole!: 'w2' | 'w3';

  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  private attackKey!: Phaser.Input.Keyboard.Key;
  private blockKey!: Phaser.Input.Keyboard.Key;

  private playerState: 'idle' | 'walk' | 'attack' | 'block' | 'hurt' | 'dead' = 'idle';
  private enemyState: 'idle' | 'walk' | 'attack' | 'block' | 'hurt' | 'dead' = 'idle';

  private isGameOver = false;

  private enemyAIEvent!: Phaser.Time.TimerEvent;

  constructor() {
    super('Game');
  }

  init(data: { role: 'w2' | 'w3' }) {
    this.playerRole = data.role;
    this.enemyRole = this.playerRole === 'w2' ? 'w3' : 'w2';
    this.isGameOver = false;
  }

  create() {
    EventBus.emit('game-started');

    const w = this.game.config.width as number;
    const h = this.game.config.height as number;

    // Background
    const bg = this.add.graphics();
    bg.fillGradientStyle(0x1A237E, 0x1A237E, 0x0D113A, 0x0D113A, 1);
    bg.fillRect(0, 0, w, h);

    // Floor line
    const floor = this.add.graphics();
    floor.lineStyle(4, 0xFF5722);
    floor.beginPath();
    floor.moveTo(0, FLOOR_HEIGHT + 48); // sprites are 96x96, offset floor to feet
    floor.lineTo(w, FLOOR_HEIGHT + 48);
    floor.strokePath();

    // Spawn player
    this.player = this.physics.add.sprite(200, FLOOR_HEIGHT, `${this.playerRole}_idle`);
    this.player.setCollideWorldBounds(true);
    (this.player.body as Phaser.Physics.Arcade.Body).setSize(30, 60);

    // Spawn enemy
    this.enemy = this.physics.add.sprite(GAME_WIDTH - 200, FLOOR_HEIGHT, `${this.enemyRole}_idle`);
    this.enemy.setCollideWorldBounds(true);
    this.enemy.setFlipX(true);
    (this.enemy.body as Phaser.Physics.Arcade.Body).setSize(30, 60);

    // Controls
    if (this.input.keyboard) {
      this.cursors = this.input.keyboard.createCursorKeys();
      this.attackKey = this.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.J);
      this.blockKey = this.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.K);
    }

    // Animation events
    this.player.on('animationupdate', (anim: Phaser.Animations.Animation, frame: Phaser.Animations.AnimationFrame) => {
      if (anim.key.endsWith('_attack') && (frame.index === 1 || frame.index === 2)) {
        this.checkHit(this.player, this.enemy, true);
      }
    });

    this.enemy.on('animationupdate', (anim: Phaser.Animations.Animation, frame: Phaser.Animations.AnimationFrame) => {
      if (anim.key.endsWith('_attack') && (frame.index === 1 || frame.index === 2)) {
        this.checkHit(this.enemy, this.player, false);
      }
    });

    this.player.on('animationcomplete', (anim: Phaser.Animations.Animation) => {
      if (anim.key.endsWith('_attack') || anim.key.endsWith('_hurt')) {
        this.player.clearTint();
        if (!this.isGameOver) {
          this.setPlayerState('idle');
        }
      }
    });

    this.enemy.on('animationcomplete', (anim: Phaser.Animations.Animation) => {
      if (anim.key.endsWith('_attack') || anim.key.endsWith('_hurt')) {
        this.enemy.clearTint();
        if (!this.isGameOver) {
          this.setEnemyState('idle');
        }
      }
    });

    // Simple AI
    this.enemyAIEvent = this.time.addEvent({
      delay: 500,
      callback: this.updateAI,
      callbackScope: this,
      loop: true
    });
  }

  update() {
    if (this.isGameOver) return;

    this.handlePlayerInput();
    this.updateFacing();
  }

  private handlePlayerInput() {
    if (this.playerState === 'hurt' || this.playerState === 'dead' || this.playerState === 'attack') {
      this.player.setVelocityX(0);
      return; // Locked state
    }

    if (this.blockKey.isDown) {
      this.setPlayerState('block');
      this.player.setVelocityX(0);
      return;
    }

    if (Phaser.Input.Keyboard.JustDown(this.attackKey)) {
      this.setPlayerState('attack');
      this.player.setVelocityX(0);
      return;
    }

    if (this.cursors.left.isDown) {
      this.setPlayerState('walk');
      this.player.setVelocityX(-PLAYER_SPEED);
    } else if (this.cursors.right.isDown) {
      this.setPlayerState('walk');
      this.player.setVelocityX(PLAYER_SPEED);
    } else {
      this.setPlayerState('idle');
      this.player.setVelocityX(0);
    }
  }

  private updateFacing() {
    if (this.isGameOver) return;
    this.player.setFlipX(this.player.x > this.enemy.x);
    this.enemy.setFlipX(this.enemy.x > this.player.x);
  }

  private setPlayerState(state: typeof this.playerState) {
    if (this.playerState === state) return;
    this.playerState = state;
    this.player.play(`${this.playerRole}_${state}`);
  }

  private setEnemyState(state: typeof this.enemyState) {
    if (this.enemyState === state) return;
    this.enemyState = state;
    this.enemy.play(`${this.enemyRole}_${state}`);
  }

  private checkHit(attacker: Phaser.Physics.Arcade.Sprite, defender: Phaser.Physics.Arcade.Sprite, isPlayerAttacking: boolean) {
    // Basic range check
    const distance = Math.abs(attacker.x - defender.x);
    if (distance > 80) return; // Attack missed

    // Only hit once per attack animation (simplified by active frame checks, but let's throttle to avoid double hits on index 1 and 2)
    // We add a custom property to avoid double hit in one attack cycle
    const attackerData = attacker.getData('hasHitInCurrentAttack');
    if (attackerData) return;
    attacker.setData('hasHitInCurrentAttack', true);

    // Reset this flag when attack completes
    attacker.once('animationcomplete', () => {
      attacker.setData('hasHitInCurrentAttack', false);
    });

    const isBlocking = isPlayerAttacking ? this.enemyState === 'block' : this.playerState === 'block';
    const rawDamage = LIGHT_ATTACK_DAMAGE;
    const finalDamage = isBlocking ? Math.floor(rawDamage * BLOCK_REDUCTION) : rawDamage;

    // Apply damage
    const store = useGameStore.getState();
    if (isPlayerAttacking) {
      const newHp = Math.max(0, store.enemyHp - finalDamage);
      store.setHp(store.playerHp, newHp);
      if (newHp <= 0) this.handleGameOver('player');
      else this.applyHurt(defender, false);
    } else {
      const newHp = Math.max(0, store.playerHp - finalDamage);
      store.setHp(newHp, store.enemyHp);
      if (newHp <= 0) this.handleGameOver('enemy');
      else this.applyHurt(defender, true);
    }
  }

  private applyHurt(sprite: Phaser.Physics.Arcade.Sprite, isPlayer: boolean) {
    sprite.setTint(0xffffff);
    if (isPlayer) {
      this.setPlayerState('hurt');
    } else {
      this.setEnemyState('hurt');
    }

    // Knockback
    const direction = sprite.x > (isPlayer ? this.enemy.x : this.player.x) ? 1 : -1;
    this.tweens.add({
      targets: sprite,
      x: sprite.x + direction * 30,
      duration: 100,
      ease: 'Power1'
    });
  }

  private updateAI() {
    if (this.isGameOver) {
      this.enemy.setVelocityX(0);
      return;
    }
    if (this.enemyState === 'hurt' || this.enemyState === 'dead' || this.enemyState === 'attack') {
      this.enemy.setVelocityX(0);
      return;
    }

    const distance = Math.abs(this.player.x - this.enemy.x);
    const rand = Math.random();

    if (distance > 70) {
      // Move closer
      this.setEnemyState('walk');
      const direction = this.player.x > this.enemy.x ? 1 : -1;
      this.enemy.setVelocityX(PLAYER_SPEED * 0.8 * direction);
    } else {
      this.enemy.setVelocityX(0);
      if (this.playerState === 'attack') {
        if (rand < 0.6) {
          this.setEnemyState('block');
        } else {
          this.setEnemyState('idle');
        }
      } else {
        if (rand < 0.4) {
          this.setEnemyState('attack');
        } else {
          this.setEnemyState('idle');
        }
      }
    }
  }

  private handleGameOver(winner: 'player' | 'enemy') {
    this.isGameOver = true;
    this.enemyAIEvent.remove(false);

    this.player.setVelocityX(0);
    this.enemy.setVelocityX(0);

    if (winner === 'player') {
      this.setEnemyState('dead');
      this.setPlayerState('idle');
    } else {
      this.setPlayerState('dead');
      this.setEnemyState('idle');
    }

    const store = useGameStore.getState();
    store.setWinner(winner);

    this.time.delayedCall(1500, () => {
      EventBus.emit('scene-changed', { key: 'GameOver' });
    });
  }

  shutdown() {
    if (this.enemyAIEvent) this.enemyAIEvent.destroy();
  }
}

