import React, { useEffect, useRef } from 'react';
import { EventBus } from './game/EventBus';
import { useGameStore } from './game/store';
import { startPhaserGame } from './game/main';
import UIOverlay from './components/UIOverlay';
import MainMenuUI from './components/MainMenuUI';
import GameOverUI from './components/GameOverUI';

function App() {
  const initialized = useRef(false);
  const status = useGameStore(state => state.status);
  const setStatus = useGameStore(state => state.setStatus);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const game = startPhaserGame();

    EventBus.on('phaser-ready', () => {
      setStatus('menu');
    });

    EventBus.on('game-started', () => {
      setStatus('playing');
    });

    EventBus.on('scene-changed', ({ key }: { key: string }) => {
      if (key === 'GameOver') {
        setStatus('gameover');
      }
    });

    return () => {
      EventBus.off('phaser-ready');
      EventBus.off('game-started');
      EventBus.off('scene-changed');
      game.destroy(true);
      initialized.current = false;
    };
  }, [setStatus]);

  return (
    <div className="w-screen h-screen bg-gray-900 flex items-center justify-center relative overflow-hidden font-sans select-none">
      {/* 
        Container must be explicit size for Phaser Scale.FIT 
        Let's use a 16:9 container that scales to fit viewport
      */}
      <div className="relative w-full max-w-[1280px] aspect-video shadow-2xl border-4 border-[#1A237E]">
        <div id="game-container" className="w-full h-full absolute inset-0" />

        {/* React UI Overlays */}
        {status === 'menu' && <MainMenuUI />}
        {status === 'playing' && <UIOverlay />}
        {status === 'gameover' && <GameOverUI />}
      </div>
    </div>
  );
}

export default App;

import React from 'react';
import { useGameStore } from '../game/store';
import { EventBus } from '../game/EventBus';

export default function MainMenuUI() {
  const setPlayerRole = useGameStore(state => state.setPlayerRole);

  const handleSelect = (role: 'w2' | 'w3') => {
    setPlayerRole(role);
    EventBus.emit('start-game', role);
  };

  return (
    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/60 z-10 p-8">
      <h1 className="text-6xl font-black text-white mb-12 drop-shadow-lg tracking-widest uppercase" style={{ WebkitTextStroke: '2px #FF5722' }}>
        K12 街机格斗
      </h1>

      <h2 className="text-3xl font-bold text-white mb-8 bg-[#1A237E] px-8 py-2 border-4 border-[#FF5722]">选择角色</h2>

      <div className="flex gap-16">
        <button 
          onClick={() => handleSelect('w2')}
          className="flex flex-col items-center group transition-transform active:translate-y-2"
        >
          <div className="w-40 h-40 bg-[#0D113A] border-4 border-[#FF5722] flex items-center justify-center group-hover:bg-[#1A237E]">
            {/* Minimal visual representation */}
            <div className="w-20 h-20 bg-blue-500 rounded-sm"></div>
          </div>
          <span className="mt-4 text-2xl font-bold text-white bg-blue-600 px-4 py-1 border-2 border-white">蓝色战士</span>
        </button>

        <button 
          onClick={() => handleSelect('w3')}
          className="flex flex-col items-center group transition-transform active:translate-y-2"
        >
          <div className="w-40 h-40 bg-[#0D113A] border-4 border-[#FF5722] flex items-center justify-center group-hover:bg-[#1A237E]">
             <div className="w-20 h-20 bg-red-500 rounded-sm"></div>
          </div>
          <span className="mt-4 text-2xl font-bold text-white bg-red-600 px-4 py-1 border-2 border-white">红色战士</span>
        </button>
      </div>

      <div className="mt-16 text-xl text-white/80 bg-black/80 px-6 py-4 border-2 border-[#FF5722]">
        <p className="font-bold text-[#FFEB3B] mb-2 text-center">操作说明：</p>
        <div className="flex gap-8">
          <span><kbd className="bg-gray-800 px-2 py-1 rounded">←</kbd> <kbd className="bg-gray-800 px-2 py-1 rounded">→</kbd> 移动</span>
          <span><kbd className="bg-gray-800 px-2 py-1 rounded">J</kbd> 轻拳</span>
          <span><kbd className="bg-gray-800 px-2 py-1 rounded">K</kbd> 按住格挡</span>
        </div>
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { useGameStore } from '../game/store';
import { MAX_HP } from '../game/constants';

export default function UIOverlay() {
  const [localPlayerHp, setLocalPlayerHp] = useState(MAX_HP);
  const [localEnemyHp, setLocalEnemyHp] = useState(MAX_HP);

  // Sync state efficiently
  useEffect(() => {
    const unsub = useGameStore.subscribe((state, prevState) => {
      if (state.playerHp !== prevState.playerHp) {
        setLocalPlayerHp(state.playerHp);
      }
      if (state.enemyHp !== prevState.enemyHp) {
        setLocalEnemyHp(state.enemyHp);
      }
    });
    return unsub;
  }, []);

  return (
    <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none z-10">

      {/* Player HP */}
      <div className="w-1/3">
        <div className="text-white text-2xl font-black mb-2 uppercase" style={{ WebkitTextStroke: '1px #000' }}>PLAYER 1</div>
        <div className="h-8 bg-[#0D113A] border-4 border-black w-full relative">
          <div 
            className="h-full bg-[#FF5722] origin-left transition-all duration-100 ease-out" 
            style={{ width: `${(localPlayerHp / MAX_HP) * 100}%` }}
          />
        </div>
      </div>

      <div className="text-5xl font-black text-[#FFEB3B] italic drop-shadow-xl" style={{ WebkitTextStroke: '2px #000' }}>
        VS
      </div>

      {/* Enemy HP */}
      <div className="w-1/3">
        <div className="text-white text-2xl font-black mb-2 uppercase text-right" style={{ WebkitTextStroke: '1px #000' }}>COM</div>
        <div className="h-8 bg-[#0D113A] border-4 border-black w-full relative flex justify-end">
          <div 
            className="h-full bg-[#FF5722] origin-right transition-all duration-100 ease-out" 
            style={{ width: `${(localEnemyHp / MAX_HP) * 100}%` }}
          />
        </div>
      </div>

    </div>
  );
}

import React from 'react';
import { useGameStore } from '../game/store';
import { EventBus } from '../game/EventBus';

export default function GameOverUI() {
  const winner = useGameStore(state => state.winner);
  const resetGame = useGameStore(state => state.resetGame);

  const isPlayerWin = winner === 'player';

  const handleRestart = () => {
    resetGame();
    // Return to main menu scene
    EventBus.emit('scene-changed', { key: 'MainMenu' });
  };

  return (
    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 z-20">

      <h1 className={`text-8xl font-black mb-12 uppercase tracking-widest ${isPlayerWin ? 'text-[#FFEB3B]' : 'text-red-500'}`} 
          style={{ WebkitTextStroke: '3px #000' }}>
        {isPlayerWin ? 'YOU WIN' : 'KO!'}
      </h1>

      <button 
        onClick={handleRestart}
        className="px-12 py-4 bg-[#FF5722] text-white text-4xl font-bold border-4 border-white shadow-[8px_8px_0_#000] active:translate-y-2 active:shadow-none transition-all"
      >
        再来一局
      </button>
    </div>
  );
}

